export interface PageMetadata {
  title: string;
  description: string;
  keywords: string;
  canonicalUrl: string;
  ogTitle: string;
  ogDescription: string;
  ogImage: string;
  ogType: string;
  twitterCard: string;
  twitterTitle: string;
  twitterDescription: string;
  twitterImage: string;
}

export interface SEOConfig {
  siteName: string;
  author: string;
  themeColor: string;
  backgroundColor: string;
  defaultLanguage: string;
  googleConsoleVerification: string;
  bingWebmasterVerification: string;
  logoUrl: string;
  routes: Record<string, Partial<PageMetadata>>;
}

const getBaseAppUrl = () => {
  if (typeof window !== 'undefined') {
    const envUrl = (import.meta as any).env?.VITE_APP_URL;
    if (envUrl) return envUrl;
    // Fallback: use origin if on landing domain, else use app subdomain
    return window.location.origin;
  }
  if (typeof process !== 'undefined' && process.env) {
    return process.env.APP_URL || "https://nytroq.com";
  }
  return "https://nytroq.com";
};

/**
 * Landing (marketing) base URL — used for canonical tags on public pages.
 */
export const LANDING_BASE_URL = (() => {
  if (typeof window !== 'undefined') return (import.meta as any).env?.VITE_APP_URL || 'https://nytroq.com';
  if (typeof process !== 'undefined' && process.env) return process.env.APP_URL || 'https://nytroq.com';
  return 'https://nytroq.com';
})();

/**
 * App subdomain base URL — used for canonical tags on authenticated app routes.
 */
export const APP_BASE_URL = (() => {
  if (typeof window !== 'undefined') return (import.meta as any).env?.VITE_APP_SUBDOMAIN_URL || 'https://app.nytroq.com';
  if (typeof process !== 'undefined' && process.env) return process.env.APP_SUBDOMAIN_URL || 'https://app.nytroq.com';
  return 'https://app.nytroq.com';
})();

export const BASE_APP_URL = getBaseAppUrl();

