/**
 * Robust fetch wrapper with cross-version Node timeout support to prevent crashes or rejections.
 */
async function safeFetchWithTimeout(url: string, options: any = {}, timeoutMs: number = 3000): Promise<Response> {
  let controller: AbortController | null = null;
  let timeoutId: any = null;

  if (typeof AbortController !== 'undefined') {
    controller = new AbortController();
    timeoutId = setTimeout(() => {
      controller?.abort();
    }, timeoutMs);
  }

  try {
    const fetchOptions = {
      ...options,
      ...(controller ? { signal: controller.signal } : {})
    };
    return await fetch(url, fetchOptions);
  } finally {
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
  }
}

