app.get('/manifest.json', (req, res) => {
  res.sendFile(path.join(process.cwd(), 'manifest.json'));
});

app.get('/robots.txt', (req, res) => {
  const host = req.hostname || '';
  const isAppSubdomain = host === 'app.nytroq.com';
  res.type('text/plain');
  if (isAppSubdomain) {
    // Prevent search engines from indexing the authenticated app
    res.send(`User-agent: *\nDisallow: /\n`);
  } else {
    // Allow indexing of landing/marketing pages, block API routes
    res.send(`User-agent: *\nAllow: /\nDisallow: /api/\n\nSitemap: ${LANDING_DOMAIN}/sitemap.xml\n`);
  }
});

app.get('/sitemap.xml', (req, res) => {
  res.type('application/xml');
  const currentDate = new Date().toISOString().split('T')[0];
  const paths = Object.keys(seoConfig.routes);
  const sitemapItems = paths.map(p => {
    const priority = p === '/' ? '1.0' : '0.8';
    const changefreq = p === '/' ? 'daily' : 'weekly';
    return `  <url>
    <loc>${BASE_APP_URL}${p === '/' ? '' : p}</loc>
    <lastmod>${currentDate}</lastmod>
    <changefreq>${changefreq}</changefreq>
    <priority>${priority}</priority>
  </url>`;
  }).join('\n');
  
  res.send(`<?xml version="1.0" encoding="UTF-8"?>
<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
${sitemapItems}
</urlset>`);
});

