// Vite HMR setup for dev mode, Static Assets for production mode
async function startViteAndExpress() {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
    log("Vite dev middleware mounted successfully on port 3000.");
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    
    app.get('*', async (req, res) => {
      const indexPath = path.join(distPath, 'index.html');
      try {
        let html = await fs.promises.readFile(indexPath, 'utf-8');
        const host = req.hostname || '';
        const isAppSubdomain = host === 'app.nytroq.com';
        const meta = getMetadataForRoute(req.path);
        
        // For the app subdomain, prevent search engine indexing of protected routes
        const robotsMeta = isAppSubdomain
          ? `\n    <meta name="robots" content="noindex, nofollow" />`
          : '';
        
        // Use correct canonical base URL per domain
        const canonicalBase = isAppSubdomain ? APP_DOMAIN : LANDING_DOMAIN;
        const canonicalPath = req.path === '/' ? '' : req.path;
        const canonicalUrl = `${canonicalBase}${canonicalPath}`;
        
        // Build dynamic metadata block to replace standard tags
        const injection = `
    <title>${meta.title}</title>
    <meta name="description" content="${meta.description}" />
    <meta name="keywords" content="${meta.keywords}" />
    <link rel="canonical" href="${canonicalUrl}" />${robotsMeta}
    
    <!-- Open Graph tags -->
    <meta property="og:title" content="${meta.ogTitle}" />
    <meta property="og:description" content="${meta.ogDescription}" />
    <meta property="og:image" content="${meta.ogImage}" />
    <meta property="og:url" content="${canonicalUrl}" />
    
    <!-- Twitter Card tags -->
    <meta name="twitter:title" content="${meta.twitterTitle}" />
    <meta name="twitter:description" content="${meta.twitterDescription}" />
    <meta name="twitter:image" content="${meta.twitterImage}" />
    
    <!-- Structured JSON-LD Data -->
    <script type="application/ld+json">
      ${JSON.stringify(getStructuredData(), null, 2)}
    </script>
        `;
        
        // Replace injection token inside head
        if (html.includes('<!-- SEO_METADATA_INJECTION_PLACEHOLDER -->')) {
          html = html.replace('<!-- SEO_METADATA_INJECTION_PLACEHOLDER -->', injection);
        }
        
        // Ensure standard static title is also dynamic to avoid double elements
        html = html.replace(/<title>.*?<\/title>/, `<title>${meta.title}</title>`);
        
        res.send(html);
      } catch (err) {
        console.error("Failed to read and compile index.html:", err);
        res.sendFile(indexPath);
      }
    });
    log("Production mode: Static file host with Server-Side SEO injection configured.");
  }

  app.listen(PORT, "0.0.0.0", () => {
    log(`SERVER ACTIVE AND INGRESS ROUTED AT http://localhost:${PORT}`);
  });
}

startViteAndExpress();
